const raw = $input.first().json || {};
let input = raw;
if (typeof raw.query === 'string') {
  try {
    input = JSON.parse(raw.query);
  } catch (error) {
    input = { summary: raw.query };
  }
}
const asString = (value) => (value === undefined || value === null ? '' : String(value).trim());
const pick = (...keys) => {
  for (const key of keys) {
    if (input[key] !== undefined && input[key] !== null && String(input[key]).trim() !== '') {
      return input[key];
    }
    if (raw[key] !== undefined && raw[key] !== null && String(raw[key]).trim() !== '') {
      return raw[key];
    }
  }
  return undefined;
};
const actionRaw = asString(pick('action', 'intent', 'operation')).toLowerCase();
const entityRaw = asString(pick('entity', 'type', 'resource')).toLowerCase();
const canonicalEntity = entityRaw.replace(/[^a-z]/g, '');
let actionKey = 'read_overview';
if (actionRaw === 'create' && canonicalEntity === 'board') actionKey = 'create_board';
else if (actionRaw === 'create' && canonicalEntity === 'list') actionKey = 'create_list';
else if (actionRaw === 'create' && canonicalEntity === 'card') actionKey = 'create_card';
else if ((actionRaw === 'update' || actionRaw === 'move') && canonicalEntity === 'card') actionKey = 'update_card';
else if (actionRaw === 'create' && (canonicalEntity === 'comment' || canonicalEntity === 'cardcomment')) actionKey = 'add_comment';
else if (['comment', 'addcomment', 'add_comment'].includes(actionRaw)) actionKey = 'add_comment';
else if (actionRaw === 'create' && canonicalEntity === 'checklist') actionKey = 'create_checklist';
else if ((actionRaw === 'update' && canonicalEntity === 'checklistitem') || ['check', 'complete', 'done'].includes(actionRaw)) actionKey = 'update_checklist_item';
else if (['read', 'review', 'status', 'get', 'list', 'lookup', 'show', 'search'].includes(actionRaw)) actionKey = 'read_overview';
const mutating = actionKey !== 'read_overview';
const confirmed = input.confirmed === true || String(input.confirmed).toLowerCase() === 'true';
const rawItems = pick('items', 'checklistItems');
let items = [];
if (Array.isArray(rawItems)) items = rawItems.map((item) => asString(item)).filter(Boolean);
else if (typeof rawItems === 'string') items = rawItems.split(/\n|,/).map((item) => item.trim()).filter(Boolean);
const title = asString(pick('title', 'newTitle', 'name'));
const cardTitle = asString(pick('cardTitle', 'cardName', 'card', 'existingTitle'));
const summary = asString(pick('summary', 'request', 'message')) || title || cardTitle || 'No action summary provided.';
const normalized = {
  actionKey,
  mutating,
  confirmed,
  summary,
  boardName: asString(pick('boardName', 'board')) || (process.env.WEDDING_BOARD_NAME || 'Wedding Planning'),
  boardId: asString(pick('boardId')),
  listName: asString(pick('listName', 'list', 'listTitle')),
  listId: asString(pick('listId')),
  moveToListName: asString(pick('moveToListName', 'targetListName', 'destinationListName', 'moveToList')),
  moveToListId: asString(pick('moveToListId', 'targetListId', 'destinationListId')),
  cardTitle,
  cardId: asString(pick('cardId')),
  title: title || (actionKey === 'create_card' ? cardTitle : ''),
  description: asString(pick('description')),
  comment: asString(pick('comment', 'note')),
  dueAt: asString(pick('dueAt', 'due', 'dueDate')),
  startAt: asString(pick('startAt', 'startDate')),
  endAt: asString(pick('endAt', 'endDate')),
  checklistTitle: asString(pick('checklistTitle', 'checklist', 'checklistName')),
  checklistId: asString(pick('checklistId')),
  checklistItemTitle: asString(pick('checklistItemTitle', 'checklistItem', 'item', 'itemTitle')),
  checklistItemId: asString(pick('checklistItemId', 'itemId')),
  swimlaneName: asString(pick('swimlaneName', 'swimlane')),
  swimlaneId: asString(pick('swimlaneId')),
  isFinished: input.isFinished === true || ['check', 'complete', 'done'].includes(actionRaw),
  items,
};
return [{ json: normalized }];

const request = $('Normalize Wekan Request').first().json;
const labels = {
  create_board: 'create the wedding board',
  create_list: 'create a list',
  create_card: 'create a card',
  update_card: 'update or move a card',
  add_comment: 'add a card comment',
  create_checklist: 'create a checklist',
  update_checklist_item: 'update a checklist item',
};
const payload = JSON.stringify({ ...request, confirmed: true });
const result =   'Confirmation required before changing Wekan. Planned action: ' + (labels[request.actionKey] || request.actionKey) +   ' on board "' + request.boardName + '". Summary: ' + request.summary +   '. After the user approves, call Wekan MCP again with the same payload and confirmed=true.';
return [{ json: { result, confirmationRequired: true, nextPayload: payload } }];

const request = $('Normalize Wekan Request').first().json;
const login = $('Login to Wekan').first().json || {};
const user = $('Get Current User').first().json || {};
const items = $('Get User Boards').all().map((item) => item.json);
const boards = (items.length === 1 && Array.isArray(items[0]) ? items[0] : items)
  .filter((entry) => entry && typeof entry === 'object' && entry._id);
const normalized = (value) => String(value || '').trim().toLowerCase();
let board = null;
if (request.boardId) board = boards.find((entry) => entry._id === request.boardId) || null;
if (!board && request.boardName) board = boards.find((entry) => normalized(entry.title) === normalized(request.boardName)) || null;
const boardId = board?._id || request.boardId || null;
return [{
  json: {
    ...request,
    token: login.token || null,
    userId: user._id || login.id || null,
    boards,
    boardId,
    boardTitle: board?.title || request.boardName,
    boardExists: Boolean(boardId),
    boardAccessible: Boolean(boardId) || request.actionKey === 'create_board',
  },
}];

const state = $('Resolve Board').first().json;
const available = (state.boards || []).map((board) => board.title).filter(Boolean);
const suffix = available.length ? ' Available boards: ' + available.join(', ') + '.' : ' No boards are currently available.';
return [{ json: { result: 'The board "' + state.boardName + '" was not found.' + suffix + ' Create it first or update WEDDING_BOARD_NAME.', confirmationRequired: false } }];

const state = $('Resolve Board').first().json;
const listItems = $('Get Board Lists').all().map((item) => item.json);
const swimlaneItems = $('Get Swimlanes').all().map((item) => item.json);
const lists = (listItems.length === 1 && Array.isArray(listItems[0]) ? listItems[0] : listItems)
  .filter((entry) => entry && typeof entry === 'object' && entry._id);
const swimlanes = (swimlaneItems.length === 1 && Array.isArray(swimlaneItems[0]) ? swimlaneItems[0] : swimlaneItems)
  .filter((entry) => entry && typeof entry === 'object' && entry._id);
const normalized = (value) => String(value || '').trim().toLowerCase();
let list = null;
if (state.listId) list = lists.find((entry) => entry._id === state.listId) || null;
if (!list && state.listName) list = lists.find((entry) => normalized(entry.title) === normalized(state.listName)) || null;
let targetList = null;
if (state.moveToListId) targetList = lists.find((entry) => entry._id === state.moveToListId) || null;
if (!targetList && state.moveToListName) targetList = lists.find((entry) => normalized(entry.title) === normalized(state.moveToListName)) || null;
let swimlane = null;
if (state.swimlaneId) swimlane = swimlanes.find((entry) => entry._id === state.swimlaneId) || null;
if (!swimlane && state.swimlaneName) swimlane = swimlanes.find((entry) => normalized(entry.title) === normalized(state.swimlaneName)) || null;
if (!swimlane) swimlane = swimlanes[0] || null;
return [{
  json: {
    ...state,
    lists,
    swimlanes,
    listId: list?._id || state.listId || null,
    listTitle: list?.title || state.listName || null,
    targetListId: targetList?._id || state.moveToListId || null,
    targetListTitle: targetList?.title || state.moveToListName || null,
    swimlaneId: swimlane?._id || state.swimlaneId || null,
    swimlaneTitle: swimlane?.title || state.swimlaneName || null,
  },
}];

const state = $('Resolve List').first().json;
const items = $('Get List Cards').all().map((item) => item.json);
const cards = (items.length === 1 && Array.isArray(items[0]) ? items[0] : items)
  .filter((entry) => entry && typeof entry === 'object' && entry._id);
const normalized = (value) => String(value || '').trim().toLowerCase();
let card = null;
if (state.cardId) card = cards.find((entry) => entry._id === state.cardId) || null;
if (!card && state.cardTitle) card = cards.find((entry) => normalized(entry.title) === normalized(state.cardTitle)) || null;
return [{
  json: {
    ...state,
    cards,
    cardId: card?._id || state.cardId || null,
    currentCardTitle: card?.title || state.cardTitle || null,
  },
}];

const state = $('Resolve Card').first().json;
const items = $('Get Card Checklists').all().map((item) => item.json);
const checklists = (items.length === 1 && Array.isArray(items[0]) ? items[0] : items)
  .filter((entry) => entry && typeof entry === 'object' && entry._id);
const normalized = (value) => String(value || '').trim().toLowerCase();
let checklist = null;
if (state.checklistId) checklist = checklists.find((entry) => entry._id === state.checklistId) || null;
if (!checklist && state.checklistTitle) checklist = checklists.find((entry) => normalized(entry.title) === normalized(state.checklistTitle)) || null;
return [{
  json: {
    ...state,
    checklists,
    checklistId: checklist?._id || state.checklistId || null,
    currentChecklistTitle: checklist?.title || state.checklistTitle || null,
  },
}];

const state = $('Resolve Checklist').first().json;
const detail = $('Get Checklist Detail').first()?.json || {};
const checklistItems = Array.isArray(detail.items) ? detail.items.filter((entry) => entry && typeof entry === 'object' && entry._id) : [];
const normalized = (value) => String(value || '').trim().toLowerCase();
let checklistItem = null;
if (state.checklistItemId) checklistItem = checklistItems.find((entry) => entry._id === state.checklistItemId) || null;
if (!checklistItem && state.checklistItemTitle) checklistItem = checklistItems.find((entry) => normalized(entry.title) === normalized(state.checklistItemTitle)) || null;
const cardUpdateFields = {};
if (state.title) cardUpdateFields.title = state.title;
if (state.description) cardUpdateFields.description = state.description;
if (state.dueAt) cardUpdateFields.dueAt = state.dueAt;
if (state.startAt) cardUpdateFields.startAt = state.startAt;
if (state.endAt) cardUpdateFields.endAt = state.endAt;
if (state.targetListId) cardUpdateFields.listId = state.targetListId;
const checklistItemUpdateFields = {};
if (state.checklistItemTitle) checklistItemUpdateFields.title = state.checklistItemTitle;
if (state.isFinished === true || state.isFinished === false) checklistItemUpdateFields.isFinished = state.isFinished;
let ready = true;
let validationMessage = '';
if (state.actionKey === 'create_board') {
  if (state.boardExists) {
    ready = false;
    validationMessage = 'The board already exists. Use the existing board instead of creating it again.';
  } else if (!state.userId) {
    ready = false;
    validationMessage = 'The Wekan user could not be resolved, so the board cannot be created yet.';
  }
} else if (state.actionKey === 'read_overview') {
  ready = Boolean(state.boardId);
  if (!ready) validationMessage = 'The requested board was not found.';
} else if (state.actionKey === 'create_list') {
  ready = Boolean(state.boardId && state.title);
  if (!ready) validationMessage = 'Creating a list needs a board and a list title.';
} else if (state.actionKey === 'create_card') {
  ready = Boolean(state.boardId && state.listId && state.swimlaneId && state.userId && state.title);
  if (!ready) validationMessage = 'Creating a card needs a board, list, swimlane, author, and card title.';
} else if (state.actionKey === 'update_card') {
  ready = Boolean(state.boardId && state.listId && state.cardId && Object.keys(cardUpdateFields).length);
  if (!ready) validationMessage = 'Updating a card needs the card plus at least one change (title, description, due date, or target list).';
} else if (state.actionKey === 'add_comment') {
  ready = Boolean(state.boardId && state.cardId && state.userId && state.comment);
  if (!ready) validationMessage = 'Adding a comment needs the card and the comment text.';
} else if (state.actionKey === 'create_checklist') {
  ready = Boolean(state.boardId && state.cardId && state.checklistTitle);
  if (!ready) validationMessage = 'Creating a checklist needs the target card and a checklist title.';
} else if (state.actionKey === 'update_checklist_item') {
  ready = Boolean(state.boardId && state.cardId && state.checklistId && (checklistItem?._id || state.checklistItemId) && Object.keys(checklistItemUpdateFields).length);
  if (!ready) validationMessage = 'Updating a checklist item needs the checklist item and at least one change.';
} else {
  ready = false;
  validationMessage = 'This Wekan action is not supported yet.';
}
return [{
  json: {
    ...state,
    checklistItems,
    checklistItemId: checklistItem?._id || state.checklistItemId || null,
    currentChecklistItemTitle: checklistItem?.title || state.checklistItemTitle || null,
    cardUpdateFields,
    checklistItemUpdateFields,
    ready,
    validationMessage,
    isCreateBoard: state.actionKey === 'create_board',
    isReadOverview: state.actionKey === 'read_overview',
    isCreateList: state.actionKey === 'create_list',
    isCreateCard: state.actionKey === 'create_card',
    isUpdateCard: state.actionKey === 'update_card',
    isAddComment: state.actionKey === 'add_comment',
    isCreateChecklist: state.actionKey === 'create_checklist',
    isUpdateChecklistItem: state.actionKey === 'update_checklist_item',
  },
}];

const state = $('Resolve Wekan Context').first().json;
const lines = [];
lines.push('Board: ' + (state.boardTitle || state.boardName) + ' (' + (state.boardId || 'unknown id') + ')');
lines.push('Lists: ' + (state.lists || []).length + ', Cards in selected list: ' + (state.cards || []).length + ', Checklists on selected card: ' + (state.checklists || []).length + '.');
if (state.listTitle) lines.push('Selected list: ' + state.listTitle + (state.listId ? ' (' + state.listId + ')' : ''));
if (state.cards && state.cards.length) {
  const previewCards = state.cards.slice(0, 8).map((card, index) => (index + 1) + '. ' + card.title);
  lines.push('Cards\n' + previewCards.join('\n'));
}
if (state.checklists && state.checklists.length) {
  const previewChecklists = state.checklists.slice(0, 5).map((checklist) => '- ' + checklist.title);
  lines.push('Checklists\n' + previewChecklists.join('\n'));
}
return [{ json: { result: lines.join('\n') } }];

const state = $('Resolve Wekan Context').first().json;
const output = $input.first().json || {};
const messages = {
  create_board: 'Created the wedding board.',
  create_list: 'Created the requested list.',
  create_card: 'Created the requested card.',
  update_card: state.targetListId ? 'Updated the card and moved it if requested.' : 'Updated the requested card.',
  add_comment: 'Added the comment to the card.',
  create_checklist: 'Created the checklist on the card.',
  update_checklist_item: 'Updated the checklist item.',
};
return [{ json: { result: messages[state.actionKey] || 'Wekan updated successfully.', data: output } }];
